import { describe, expect, it } from 'vitest';
import {
  attachStyleTransferEnsembleToMeshCarrierAssessmentJson,
  encodeMeshCarrierAssessmentV1Json,
  mergeStyleTransferFoldIntoMeshCarrierJson,
  styleTransferEnsembleResultToMeshCarrierFold,
} from '../src/mesh-carrier-assessment';
import type { StyleTransferEnsembleResult } from '../src/style-transfer-types';
import { classifySpectralNoise, type LayerNodeTrace } from '../src/spectral-noise-monitor';

function spectralOk(id: string) {
  const trace: LayerNodeTrace = {
    requestId: id,
    nodeIdx: 0,
    chunkIdx: 0,
    startPos: 0,
    sequenceLength: 8,
    latencyMs: 1,
    expectedLatencyMs: 10,
    requestEntropy: 0.5,
    boundaryLimit: 6,
    timestamp: 1,
  };
  return classifySpectralNoise(trace);
}

describe('mesh carrier style transfer fold', () => {
  it('round-trips styleTransferFold on mesh carrier JSON', () => {
    const spectral = spectralOk('r');
    const base = encodeMeshCarrierAssessmentV1Json({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral,
    });
    const mock: StyleTransferEnsembleResult = {
      stylized: new Float32Array(12),
      width: 2,
      height: 2,
      channels: 3,
      candidates: [
        {
          label: 'a',
          methodUsed: 'classical',
          rank: 0,
          buleyWeight: 0.6,
          rejectedByCeiling: false,
          styleDistance: 0.2,
          compositeFoldScore: 0.25,
          meshFoldMetrics: {
            mean_topology_alpha: 0.9,
            mean_depth_confidence: 1,
            mean_effective_gate: 0.8,
            gate_violation_score: 0.2,
          },
        },
        {
          label: 'b',
          methodUsed: 'classical',
          rank: 1,
          buleyWeight: 0.4,
          rejectedByCeiling: false,
          styleDistance: 0.3,
          compositeFoldScore: 0.31,
          meshFoldMetrics: {
            mean_topology_alpha: 0.85,
            mean_depth_confidence: 1,
            mean_effective_gate: 0.75,
            gate_violation_score: 0.25,
          },
        },
      ],
      fold: { rounds: 2, survivors: 2, rejected: 0, totalWeight: 1 },
    };
    const fold = styleTransferEnsembleResultToMeshCarrierFold(mock);
    expect(fold.compositeScores).toEqual([0.25, 0.31]);
    const merged = mergeStyleTransferFoldIntoMeshCarrierJson(base, fold);
    const parsed = JSON.parse(merged) as { styleTransferFold?: { candidateLabels: string[] } };
    expect(parsed.styleTransferFold?.candidateLabels).toEqual(['a', 'b']);
  });

  it('attachStyleTransferEnsemble merges into existing assessment', () => {
    const spectral = spectralOk('r2');
    const json = encodeMeshCarrierAssessmentV1Json({
      stationLayerStart: 0,
      stationLayerEndExclusive: 1,
      spectral,
    });
    const mock: StyleTransferEnsembleResult = {
      stylized: new Float32Array(12),
      width: 2,
      height: 2,
      channels: 3,
      candidates: [
        {
          label: 'x',
          methodUsed: 'classical',
          rank: 0,
          buleyWeight: 1,
          rejectedByCeiling: false,
          styleDistance: 0.1,
        },
      ],
      fold: { rounds: 1, survivors: 1, rejected: 0, totalWeight: 1 },
    };
    const out = attachStyleTransferEnsembleToMeshCarrierAssessmentJson(json, mock);
    expect(JSON.parse(out).styleTransferFold).toBeDefined();
  });
});
